#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#ifdef TIMING
#include "timing.h"
#endif

#define MAX_THREADS_PER_BLOCK 512

int no_of_nodes;
int edge_list_size;
FILE *fp;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

struct Node
{
    int starting;
    int no_of_edges;
};

void Kernel(Node *g_graph_nodes, int *g_graph_edges, bool *g_graph_mask,
            bool *g_updating_graph_mask, bool *g_graph_visited, int *v_0,
            int no_of_nodes)
{
#pragma omp parallel for schedule(static)
    for (int tid = 0; tid < no_of_nodes; tid++)
    {
        if (g_graph_mask[tid])
        {
            g_graph_mask[tid] = false;
            for (int i = g_graph_nodes[tid].starting;
                 i < (g_graph_nodes[tid].no_of_edges + g_graph_nodes[tid].starting); i++)
            {
                int id = g_graph_edges[i];
                if (!g_graph_visited[id])
                {
                    v_0[id] = v_0[tid] + 1;
                    g_updating_graph_mask[id] = true;
                }
            }
        }
    }
}

void Kernel2(bool *g_graph_mask, bool *g_updating_graph_mask,
             bool *g_graph_visited, bool *g_over, int no_of_nodes)
{
    int over_local = 0;
#pragma omp parallel for reduction(| : over_local) schedule(static)
    for (int tid = 0; tid < no_of_nodes; tid++)
    {
        if (g_updating_graph_mask[tid])
        {
            g_graph_mask[tid] = true;
            g_graph_visited[tid] = true;
            over_local = 1;
            g_updating_graph_mask[tid] = false;
        }
    }
    *g_over = (over_local != 0);
}

void BFSGraph(int argc, char **argv);

int main(int argc, char **argv)
{
    no_of_nodes = 0;
    edge_list_size = 0;
    BFSGraph(argc, argv);
    return 0;
}

void Usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <input_file>\n", argv[0]);
}

void BFSGraph(int argc, char **argv)
{
    char *input_f;
    if (argc != 2)
    {
        Usage(argc, argv);
        exit(0);
    }

    input_f = argv[1];
    printf("Reading File\n");

    fp = fopen(input_f, "r");
    if (!fp)
    {
        printf("Error Reading graph file\n");
        return;
    }

    int source = 0;

    fscanf(fp, "%d", &no_of_nodes);

    int num_of_blocks = 1;
    int num_of_threads_per_block = no_of_nodes;

    if (no_of_nodes > MAX_THREADS_PER_BLOCK)
    {
        num_of_blocks = (int)ceil(no_of_nodes / (double)MAX_THREADS_PER_BLOCK);
        num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
    }

    Node *h_graph_nodes = (Node *)malloc(sizeof(Node) * no_of_nodes);
    bool *h_graph_mask = (bool *)malloc(sizeof(bool) * no_of_nodes);
    bool *h_updating_graph_mask = (bool *)malloc(sizeof(bool) * no_of_nodes);
    bool *h_graph_visited = (bool *)malloc(sizeof(bool) * no_of_nodes);

    int start, edgeno;

    for (unsigned int i = 0; i < (unsigned int)no_of_nodes; i++)
    {
        fscanf(fp, "%d %d", &start, &edgeno);
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i] = false;
        h_updating_graph_mask[i] = false;
        h_graph_visited[i] = false;
    }

    fscanf(fp, "%d", &source);
    source = 0;

    h_graph_mask[source] = true;
    h_graph_visited[source] = true;

    fscanf(fp, "%d", &edge_list_size);

    int id, cost;
    int *h_graph_edges = (int *)malloc(sizeof(int) * edge_list_size);
    for (int i = 0; i < edge_list_size; i++)
    {
        fscanf(fp, "%d", &id);
        fscanf(fp, "%d", &cost);
        h_graph_edges[i] = id;
    }

    if (fp)
        fclose(fp);

    printf("Read File\n");

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    Node *d_graph_nodes = (Node *)malloc(sizeof(Node) * no_of_nodes);
    memcpy(d_graph_nodes, h_graph_nodes, sizeof(Node) * no_of_nodes);

    int *d_graph_edges = (int *)malloc(sizeof(int) * edge_list_size);
    memcpy(d_graph_edges, h_graph_edges, sizeof(int) * edge_list_size);

    bool *d_graph_mask = (bool *)malloc(sizeof(bool) * no_of_nodes);
    memcpy(d_graph_mask, h_graph_mask, sizeof(bool) * no_of_nodes);

    bool *d_updating_graph_mask = (bool *)malloc(sizeof(bool) * no_of_nodes);
    memcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(bool) * no_of_nodes);

    bool *d_graph_visited = (bool *)malloc(sizeof(bool) * no_of_nodes);
    memcpy(d_graph_visited, h_graph_visited, sizeof(bool) * no_of_nodes);

    int *h_cost = (int *)malloc(sizeof(int) * no_of_nodes);
    for (int i = 0; i < no_of_nodes; i++)
        h_cost[i] = -1;
    h_cost[source] = 0;

    int *d_cost = (int *)malloc(sizeof(int) * no_of_nodes);
    memcpy(d_cost, h_cost, sizeof(int) * no_of_nodes);

    bool *d_over = (bool *)malloc(sizeof(bool));

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_total_start, &tv);
    h2d_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    printf("Copied Everything to GPU memory\n");

    (void)num_of_blocks;
    (void)num_of_threads_per_block;

    int k = 0;
    printf("Start traversing the tree\n");
    bool stop;

    do
    {
        stop = false;
#ifdef TIMING
        gettimeofday(&tv_h2d_start, NULL);
#endif
        memcpy(d_over, &stop, sizeof(bool));
#ifdef TIMING
        gettimeofday(&tv_h2d_end, NULL);
        tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
        h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        Kernel(d_graph_nodes, d_graph_edges, d_graph_mask, d_updating_graph_mask,
               d_graph_visited, d_cost, no_of_nodes);

        Kernel2(d_graph_mask, d_updating_graph_mask, d_graph_visited, d_over, no_of_nodes);

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_h2d_end, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        memcpy(&stop, d_over, sizeof(bool));
#ifdef TIMING
        gettimeofday(&tv_d2h_end, NULL);
        tvsub(&tv_d2h_end, &tv_kernel_end, &tv);
        d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        k++;
    } while (stop);

    printf("Kernel Executed %d times\n", k);

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    memcpy(h_cost, d_cost, sizeof(int) * no_of_nodes);
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    FILE *fpo = fopen("result.txt", "w");
    for (int i = 0; i < no_of_nodes; i++)
        fprintf(fpo, "%d) cost:%d\n", i, h_cost[i]);
    fclose(fpo);
    printf("Result stored in result.txt\n");

    free(h_graph_nodes);
    free(h_graph_edges);
    free(h_graph_mask);
    free(h_updating_graph_mask);
    free(h_graph_visited);
    free(h_cost);
#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    free(d_graph_nodes);
    free(d_graph_edges);
    free(d_graph_mask);
    free(d_updating_graph_mask);
    free(d_graph_visited);
    free(d_cost);
    free(d_over);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
